import React, { useEffect, useState, useMemo, useRef } from 'react';
import axios from 'axios';
import Header from './Header';
import * as XLSX from 'xlsx';
import { FaSearch, FaEllipsisV, FaFileExcel, FaBoxOpen, FaTags, FaBarcode, FaWeightHanging, FaMapMarkerAlt, FaCheckCircle, FaFilter, FaTimes, FaChevronDown } from 'react-icons/fa';
import { toast } from 'react-toastify';

const API_URL = 'https://rrgold.loyalstring.co.in/api/ProductMaster/GetAllLabeledStock';
const PAGE_SIZE = 15;

const Inventory = () => {
  const [activeTab, setActiveTab] = useState('labelList');
  const [deviceId, setDeviceId] = useState('');
  const [rfidDetails, setRfidDetails] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [labels, setLabels] = useState([]);
  const [search, setSearch] = useState('');
  const [filters, setFilters] = useState({});
  const [page, setPage] = useState(1);
  const searchInputRef = useRef(null);
  const [selectedRows, setSelectedRows] = useState([]);
  const [showFilter, setShowFilter] = useState(false);
  const [showExportSuccess, setShowExportSuccess] = useState(false);

  // Refs for outside click
  const filterPopupRef = useRef(null);
  const filterBtnRef = useRef(null);

  // Get userInfo from localStorage
  const [userInfo, setUserInfo] = useState({});
  useEffect(() => {
    const stored = localStorage.getItem('userInfo');
    if (stored) {
      try {
        setUserInfo(JSON.parse(stored));
      } catch {}
    }
  }, []);

  // Close filter popup on outside click
  useEffect(() => {
    if (!showFilter) return;
    function handleClick(e) {
      if (
        filterPopupRef.current &&
        !filterPopupRef.current.contains(e.target) &&
        filterBtnRef.current &&
        !filterBtnRef.current.contains(e.target)
      ) {
        setFilterAnim(false);
        setTimeout(() => setShowFilter(false), 200);
      }
    }
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, [showFilter]);

  // Responsive helper
  const isMobile = window.innerWidth < 600;

  // Animation for filter dropdown
  const [filterAnim, setFilterAnim] = useState(false);
  const openFilter = () => { setShowFilter(true); setTimeout(() => setFilterAnim(true), 10); };
  const closeFilter = () => { setFilterAnim(false); setTimeout(() => setShowFilter(false), 200); };

  // Table header and cell styles
  const thStyle = {
    fontWeight: 700,
    color: '#222',
    background: '#f4f8ff',
    fontSize: 14,
    padding: '6px 8px',
    border: 'none',
    minWidth: 80,
    textAlign: 'left',
    verticalAlign: 'middle',
    fontFamily: 'Poppins, Inter, sans-serif',
    letterSpacing: 0.1,
    height: 36,
    whiteSpace: 'nowrap',
  };

  const tdStyle = {
    padding: '6px 8px',
    border: 'none',
    minWidth: 80,
    textAlign: 'left',
    verticalAlign: 'middle',
    fontFamily: 'Poppins, Inter, sans-serif',
    fontSize: 13,
    height: 32,
    color: '#222',
    fontWeight: 500,
    letterSpacing: 0.1,
    whiteSpace: 'nowrap',
  };

  useEffect(() => {
    if (!userInfo.ClientCode) return;
    setLoading(true);
    setError('');
    axios.post(API_URL, { ClientCode: userInfo.ClientCode })
      .then(res => {
        if (Array.isArray(res.data)) {
          setLabels(res.data);
        } else if (res.data && Array.isArray(res.data.Data)) {
          setLabels(res.data.Data);
        } else {
          setLabels([]);
        }
      })
      .catch(err => {
        setError(err.response?.data?.Message || 'Failed to fetch label list');
      })
      .finally(() => setLoading(false));
  }, [userInfo.ClientCode]);

  // Filtering and searching
  const filteredLabels = useMemo(() => {
    let data = labels;
    // Search
    if (search) {
      const s = search.toLowerCase();
      data = data.filter(l =>
        (l.ItemCode && l.ItemCode.toLowerCase().includes(s)) ||
        (l.ProductName && l.ProductName.toLowerCase().includes(s)) ||
        (l.BranchName && l.BranchName.toLowerCase().includes(s))
      );
    }
    // Column filters
    Object.entries(filters).forEach(([key, value]) => {
      if (value) {
        data = data.filter(l => (l[key] || '').toString().toLowerCase().includes(value.toLowerCase()));
      }
    });
    return data;
  }, [labels, search, filters]);

  // Pagination
  let paginatedLabels = filteredLabels;
  let totalPages = 1;
  if (!search) {
    totalPages = Math.ceil(filteredLabels.length / PAGE_SIZE);
    paginatedLabels = filteredLabels.slice((page - 1) * PAGE_SIZE, page * PAGE_SIZE);
  }

  // Unique values for filters
  const getUnique = (key) => [...new Set(labels.map(l => l[key]).filter(Boolean))];

  // Handle filter change
  const handleFilterChange = (key, value) => {
    setFilters(f => ({ ...f, [key]: value }));
    setPage(1);
  };

  // Handle search change
  const handleSearchChange = (e) => {
    setSearch(e.target.value);
    setPage(1);
  };

  // Handle page change
  const handlePageChange = (newPage) => {
    if (newPage >= 1 && newPage <= totalPages) setPage(newPage);
  };

  // Export to Excel
  const handleExport = () => {
    const exportData = filteredLabels.map(({ Id, ...rest }) => rest); // Remove Id if not needed
    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Inventory');
    XLSX.writeFile(wb, 'inventory.xlsx');
    setShowExportSuccess(true);
  };

  // Selection state
  const allSelected = paginatedLabels.length > 0 && paginatedLabels.every(l => selectedRows.includes(l.Id));
  const toggleSelectAll = () => {
    if (allSelected) setSelectedRows(selectedRows.filter(id => !paginatedLabels.some(l => l.Id === id)));
    else setSelectedRows([...new Set([...selectedRows, ...paginatedLabels.map(l => l.Id)])]);
  };
  const toggleSelectRow = (id) => {
    setSelectedRows(selectedRows.includes(id) ? selectedRows.filter(i => i !== id) : [...selectedRows, id]);
  };

  // Unified filter dropdown state
  const handleFilterChangeUnified = (key, value) => {
    setFilters(f => ({ ...f, [key]: value }));
    setPage(1);
  };

  const handleGetRFIDDetails = async () => {
    if (!deviceId.trim()) {
      toast.error('Please enter a Device ID');
      return;
    }

    setLoading(true);
    try {
      const response = await fetch('https://rrgold.loyalstring.co.in/api/RFIDDevice/GetAllRFIDDetails', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          ClientCode: userInfo.ClientCode,
          DeviceId: deviceId
        })
      });

      const data = await response.json();
      if (data && Array.isArray(data)) {
        setRfidDetails(data);
        toast.success('RFID details fetched successfully');
      } else {
        setRfidDetails([]);
        toast.info('No RFID details found');
      }
    } catch (error) {
      console.error('Error fetching RFID details:', error);
      toast.error('Failed to fetch RFID details');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #f8f9fa 0%, #e9ecef 100%)',
      display: 'flex',
      flexDirection: 'column'
    }}>
      <Header userInfo={userInfo} />
      <div className="container py-4" style={{ maxWidth: '1400px' }}>
        <div className="card shadow-lg border-0" style={{ borderRadius: '15px' }}>
          <div className="card-body p-0">
            {/* Tabs */}
            <div className="d-flex border-bottom">
              <button
                className={`btn flex-grow-1 py-3 ${activeTab === 'labelList' ? 'btn-primary' : 'btn-light'}`}
                onClick={() => setActiveTab('labelList')}
                style={{ borderRadius: '15px 0 0 0' }}
              >
                <i className="fas fa-tags me-2"></i>
                Label List
              </button>
              <button
                className={`btn flex-grow-1 py-3 ${activeTab === 'rfidDetails' ? 'btn-primary' : 'btn-light'}`}
                onClick={() => setActiveTab('rfidDetails')}
                style={{ borderRadius: '0 15px 0 0' }}
              >
                <i className="fas fa-mobile-alt me-2"></i>
                RFID Device Details
              </button>
            </div>

            {/* Content */}
            <div className="p-4">
              {activeTab === 'labelList' ? (
                <div>
                  <h5 className="mb-4">Label Stock List</h5>
                  {/* Top bar */}
                  <div className={isMobile ? 'd-flex flex-column align-items-stretch mb-6 px-2' : 'd-flex flex-wrap align-items-center justify-content-between mb-6 px-2'} style={{ maxWidth: 1300, margin: '0 auto', gap: isMobile ? 12 : 0 }}>
                    {/* Search */}
                    <div className="d-flex align-items-center mb-2 mb-md-0" style={{ flex: 1 }}>
                      <div style={{ position: 'relative', width: isMobile ? '100%' : 340 }}>
                        <input
                          type="text"
                          placeholder="Search by Product Name, Category, SKU..."
                          value={search}
                          onChange={handleSearchChange}
                          style={{
                            borderRadius: 10,
                            border: '1.5px solid #e5e7eb',
                            padding: '10px 16px 10px 44px',
                            width: '100%',
                            boxShadow: '0 1.5px 6px #0001',
                            fontSize: 15,
                            background: '#fff',
                            fontFamily: 'Poppins, Inter, sans-serif',
                            outline: 'none',
                            transition: 'box-shadow 0.2s',
                            fontWeight: 500
                          }}
                          onFocus={e => e.target.style.boxShadow = '0 2px 8px #2563eb22'}
                          onBlur={e => e.target.style.boxShadow = '0 1.5px 6px #0001'}
                        />
                        <span style={{
                          position: 'absolute', left: 16, top: '50%', transform: 'translateY(-50%)',
                          color: '#9ca3af', fontSize: 20
                        }}>
                          <FaSearch />
                        </span>
                      </div>
                    </div>
                    {/* Export and Filter Buttons */}
                    <div className={isMobile ? 'd-flex flex-column gap-2 mt-3' : 'd-flex align-items-center gap-3'} style={{ width: isMobile ? '100%' : 'auto', justifyContent: isMobile ? 'center' : 'flex-end' }}>
                      <button
                        onClick={handleExport}
                        style={{
                          border: 'none',
                          color: '#fff',
                          background: 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)',
                          borderRadius: 10,
                          fontWeight: 700,
                          height: 44,
                          fontSize: 15,
                          padding: '0 26px',
                          width: isMobile ? '100%' : 'auto',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          transition: 'background 0.2s, transform 0.2s',
                          boxShadow: '0 2px 12px #0078d422',
                          marginRight: isMobile ? 0 : 0,
                          gap: 10,
                          fontFamily: 'Poppins, Inter, sans-serif',
                          letterSpacing: 0.1
                        }}
                        onMouseOver={e => { e.currentTarget.style.background = 'linear-gradient(90deg, #d60000 0%, #0078d4 100%)'; e.currentTarget.style.transform = 'scale(1.04)'; }}
                        onMouseOut={e => { e.currentTarget.style.background = 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)'; e.currentTarget.style.transform = 'scale(1)'; }}
                      >
                        <FaFileExcel style={{ marginRight: 8 }} /> Export to Excel
                      </button>
                      <button
                        ref={filterBtnRef}
                        onClick={openFilter}
                        style={{
                          border: '2px solid #0078d4',
                          color: '#0078d4',
                          background: '#fff',
                          borderRadius: 10,
                          fontWeight: 700,
                          height: 44,
                          fontSize: 15,
                          padding: '0 26px',
                          width: isMobile ? '100%' : 'auto',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          transition: 'background 0.2s, color 0.2s, transform 0.2s',
                          boxShadow: '0 2px 8px #0078d411',
                          gap: 10,
                          fontFamily: 'Poppins, Inter, sans-serif',
                          letterSpacing: 0.1
                        }}
                        onMouseOver={e => { e.currentTarget.style.background = 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)'; e.currentTarget.style.color = '#fff'; e.currentTarget.style.transform = 'scale(1.04)'; }}
                        onMouseOut={e => { e.currentTarget.style.background = '#fff'; e.currentTarget.style.color = '#0078d4'; e.currentTarget.style.transform = 'scale(1)'; }}
                      >
                        <FaFilter style={{ marginRight: 8 }} /> Filter
                      </button>
                      {showFilter && (
                        <>
                          {/* Overlay */}
                          <div style={{
                            position: 'fixed',
                            top: 0,
                            left: 0,
                            width: '100vw',
                            height: '100vh',
                            background: 'rgba(30,40,60,0.18)',
                            zIndex: 1000,
                            transition: 'opacity 0.2s',
                            opacity: filterAnim ? 1 : 0,
                            pointerEvents: filterAnim ? 'auto' : 'none',
                          }} />
                          {/* Centered Popup */}
                          <div
                            ref={filterPopupRef}
                            style={{
                              position: 'fixed',
                              top: '50%',
                              left: '50%',
                              transform: filterAnim ? 'translate(-50%, -50%) scale(1)' : 'translate(-50%, -60%) scale(0.98)',
                              background: 'linear-gradient(135deg, #fff 0%, #f8f9fa 100%)',
                              borderRadius: 20,
                              boxShadow: '0 12px 48px #0078d422, 0 2px 8px #60a5fa11',
                              padding: 0,
                              minWidth: isMobile ? 320 : 600,
                              zIndex: 1100,
                              border: '2.5px solid #0078d4',
                              display: 'flex',
                              flexDirection: 'column',
                              overflow: 'hidden',
                              fontFamily: 'Poppins, Inter, sans-serif',
                              opacity: filterAnim ? 1 : 0,
                              transition: 'opacity 0.2s, transform 0.2s',
                              backgroundClip: 'padding-box',
                            }}
                          >
                            {/* Gradient Top Bar */}
                            <div style={{
                              height: 8,
                              width: '100%',
                              background: 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)',
                              borderTopLeftRadius: 20,
                              borderTopRightRadius: 20,
                            }} />
                            <button onClick={closeFilter} style={{ position: 'absolute', top: 14, right: 18, background: 'none', border: 'none', color: '#0078d4', fontSize: 28, cursor: 'pointer', zIndex: 2, fontWeight: 700, transition: 'color 0.2s' }}><FaTimes style={{ color: '#0078d4' }} /></button>
                            <div style={{ padding: '32px 32px 16px 32px', display: 'flex', flexDirection: 'column', gap: 18 }}>
                              <div style={{ fontWeight: 800, fontSize: 24, marginBottom: 8, letterSpacing: 0.2, textAlign: 'center', background: 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>Filter Inventory</div>
                              <div style={{
                                display: 'grid',
                                gridTemplateColumns: isMobile ? '1fr' : '1fr 1fr',
                                gap: 18,
                                maxHeight: 400,
                                overflowY: 'auto',
                              }}>
                                {/* Dropdowns for fields with limited values */}
                                {[
                                  ['Product Name', 'ProductName'],
                                  ['Category', 'CategoryName'],
                                  ['Design', 'DesignName'],
                                  ['Purity', 'PurityName'],
                                  ['Box Name', 'BoxName'],
                                  ['Vendor', 'VendorName'],
                                  ['Branch', 'BranchName'],
                                  ['Status', 'Status'],
                                ].map(([label, key]) => (
                                  <div key={key}>
                                    <label style={{ fontWeight: 600, background: 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', fontSize: 15, marginBottom: 4, display: 'block' }}>{label}</label>
                                    <select className="form-select form-select-sm mb-2" style={{ borderRadius: 8, padding: '10px 14px', fontSize: 15, border: '1.5px solid #0078d455', background: '#f4f8ff', outline: 'none', width: '100%', color: '#222' }} value={filters[key] || ''} onChange={e => handleFilterChangeUnified(key, e.target.value)}><option value="">All</option>{getUnique(key).map(val => <option key={val} value={val}>{val}</option>)}</select>
                                  </div>
                                ))}
                                {/* Text inputs for other fields */}
                                {[
                                  ['Item Code', 'ItemCode'],
                                  ['RFID Code', 'RFIDCode'],
                                  ['SKU', 'SKU'],
                                  ['Gross Wt', 'GrossWt'],
                                  ['Stone Wt', 'StoneWt'],
                                  ['Stone Pcs', 'StonePcs'],
                                  ['Diamond Wt', 'DiamondWt'],
                                  ['Diamond Pcs', 'DiamondPcs'],
                                  ['Net Wt', 'NetWt'],
                                  ['Pieces', 'Pieces'],
                                  ['Stone Amt', 'StoneAmt'],
                                  ['Fixed Wastage', 'FixedWastage'],
                                  ['Fixed Amt', 'FixedAmt'],
                                  ['Created Date', 'CreatedOn'],
                                  ['Packing Weight', 'PackingWeight'],
                                  ['Total Weight', 'TotalWeight'],
                                ].map(([label, key]) => (
                                  <div key={key}>
                                    <label style={{ fontWeight: 600, background: 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', fontSize: 15, marginBottom: 4, display: 'block' }}>{label}</label>
                                    <input
                                      className="form-control form-control-sm mb-2"
                                      style={{ borderRadius: 8, padding: '10px 14px', fontSize: 15, border: '1.5px solid #0078d455', background: '#f4f8ff', outline: 'none', width: '100%', color: '#222' }}
                                      value={filters[key] || ''}
                                      onChange={e => handleFilterChangeUnified(key, e.target.value)}
                                      placeholder={`Search ${label}`}
                                    />
                                  </div>
                                ))}
                              </div>
                              <a href="#" onClick={e => { e.preventDefault(); setFilters({}); }} style={{ color: '#0078d4', fontWeight: 600, fontSize: 15, marginTop: 8, textDecoration: 'underline', alignSelf: 'flex-end' }}>Reset Filters</a>
                            </div>
                          </div>
                        </>
                      )}
                    </div>
                  </div>
                  {/* Table */}
                  <div className="overflow-x-auto" style={{ maxWidth: 1400, margin: '32px auto 8px auto', padding: 16, boxSizing: 'border-box', background: '#fff', borderRadius: 16, boxShadow: '0 6px 24px rgba(0,0,0,0.07)', fontFamily: 'Poppins, Inter, sans-serif', display: 'flex', flexDirection: 'column', justifyContent: 'flex-start', minHeight: 200 }}>
                    <table className="table align-middle mb-0" style={{ width: '100%', minWidth: 1200, background: '#fff', borderRadius: 16, overflow: 'hidden', borderCollapse: 'separate', borderSpacing: 0, fontSize: '1rem', fontFamily: 'Poppins, Inter, sans-serif', tableLayout: 'auto' }}>
                      <thead style={{ background: '#f4f8ff', borderTopLeftRadius: 16, borderTopRightRadius: 16, boxShadow: '0 2px 8px #0001' }}>
                        <tr style={{ borderRadius: 16, height: 36 }}>
                          <th style={{ ...thStyle, width: 40 }}>Sr No</th>
                          <th style={{ ...thStyle, width: 90 }}>Item Code</th>
                          <th style={{ ...thStyle, width: 110 }}>RFID Code</th>
                          <th style={{ ...thStyle, width: 80 }}>SKU</th>
                          <th style={{ ...thStyle, minWidth: 120 }}>Product Name</th>
                          <th style={{ ...thStyle, minWidth: 90 }}>Category</th>
                          <th style={{ ...thStyle, minWidth: 90 }}>Design</th>
                          <th style={{ ...thStyle, width: 70 }}>Purity</th>
                          <th style={{ ...thStyle, width: 80 }}>Gross Wt</th>
                          <th style={{ ...thStyle, width: 80 }}>Stone Wt</th>
                          <th style={{ ...thStyle, width: 80 }}>Stone Pcs</th>
                          <th style={{ ...thStyle, width: 90 }}>Diamond Wt</th>
                          <th style={{ ...thStyle, width: 90 }}>Diamond Pcs</th>
                          <th style={{ ...thStyle, width: 80 }}>Net Wt</th>
                          <th style={{ ...thStyle, width: 70 }}>Pieces</th>
                          <th style={{ ...thStyle, width: 90 }}>Stone Amt</th>
                          <th style={{ ...thStyle, width: 110 }}>Fixed Wastage</th>
                          <th style={{ ...thStyle, width: 90 }}>Fixed Amt</th>
                          <th style={{ ...thStyle, minWidth: 90 }}>Box Name</th>
                          <th style={{ ...thStyle, minWidth: 90 }}>Vendor</th>
                          <th style={{ ...thStyle, minWidth: 90 }}>Branch</th>
                          <th style={{ ...thStyle, minWidth: 110 }}>Created Date</th>
                          <th style={{ ...thStyle, width: 110 }}>Packing Weight</th>
                          <th style={{ ...thStyle, width: 110 }}>Total Weight</th>
                          <th style={{ ...thStyle, minWidth: 80 }}>Status</th>
                        </tr>
                      </thead>
                      <tbody>
                        {paginatedLabels.map((label, idx) => (
                          <tr key={label.Id} style={{ background: idx % 2 === 0 ? '#f7f7f7' : '#fff', transition: 'background 0.2s', cursor: 'pointer', borderBottom: '1.5px solid #e0e0e0', height: 32 }}
                            onMouseOver={e => e.currentTarget.style.background = '#e6f0ff'}
                            onMouseOut={e => e.currentTarget.style.background = idx % 2 === 0 ? '#f7f7f7' : '#fff'}
                          >
                            <td style={{ ...tdStyle, width: 40, textAlign: 'center', fontWeight: 600 }}>{(page - 1) * PAGE_SIZE + idx + 1}</td>
                            <td style={{ ...tdStyle, width: 90 }}>{label.ItemCode}</td>
                            <td style={{ ...tdStyle, width: 110 }}>{label.RFIDCode}</td>
                            <td style={{ ...tdStyle, width: 80 }}>{label.SKU}</td>
                            <td style={{ ...tdStyle, minWidth: 120 }}>{label.ProductName}</td>
                            <td style={{ ...tdStyle, minWidth: 90 }}>{label.CategoryName || label.Category}</td>
                            <td style={{ ...tdStyle, minWidth: 90 }}>{label.DesignName}</td>
                            <td style={{ ...tdStyle, width: 70 }}>{label.PurityName}</td>
                            <td style={{ ...tdStyle, width: 80 }}>{label.GrossWt}</td>
                            <td style={{ ...tdStyle, width: 80 }}>{label.StoneWt}</td>
                            <td style={{ ...tdStyle, width: 80 }}>{label.StonePcs}</td>
                            <td style={{ ...tdStyle, width: 90 }}>{label.DiamondWt}</td>
                            <td style={{ ...tdStyle, width: 90 }}>{label.DiamondPcs}</td>
                            <td style={{ ...tdStyle, width: 80 }}>{label.NetWt}</td>
                            <td style={{ ...tdStyle, width: 70 }}>{label.Pieces}</td>
                            <td style={{ ...tdStyle, width: 90 }}>{label.StoneAmt}</td>
                            <td style={{ ...tdStyle, width: 110 }}>{label.FixedWastage}</td>
                            <td style={{ ...tdStyle, width: 90 }}>{label.FixedAmt}</td>
                            <td style={{ ...tdStyle, minWidth: 90 }}>{label.BoxName}</td>
                            <td style={{ ...tdStyle, minWidth: 90 }}>{label.VendorName}</td>
                            <td style={{ ...tdStyle, minWidth: 90 }}>{label.BranchName || label.Branch}</td>
                            <td style={{ ...tdStyle, minWidth: 110 }}>{label.CreatedOn ? new Date(label.CreatedOn).toLocaleDateString() : ''}</td>
                            <td style={{ ...tdStyle, width: 110 }}>{label.PackingWeight}</td>
                            <td style={{ ...tdStyle, width: 110 }}>{label.TotalWeight}</td>
                            <td style={{ ...tdStyle, minWidth: 80 }}>
                              <span className={`badge`} style={{
                                background: label.Status === 'Active' ? '#d4f7df' : '#ffe5e5',
                                color: label.Status === 'Active' ? '#2ecc71' : '#e74c3c',
                                fontWeight: 700,
                                fontSize: 12,
                                padding: '2px 8px',
                                borderRadius: 12,
                                border: 'none',
                                letterSpacing: 0.2,
                                minWidth: 50,
                                display: 'inline-block',
                                textAlign: 'center',
                                fontFamily: 'Poppins, Inter, sans-serif'
                              }}>{label.Status}</span>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                  {/* Pagination below table card, compact and right-aligned */}
                  {totalPages > 1 && !search && (
                    <div className="d-flex justify-content-end align-items-center" style={{ marginTop: 12, marginBottom: 24, maxWidth: 1400, marginLeft: 'auto', marginRight: 'auto', padding: '0 16px', boxSizing: 'border-box', background: '#fff' }}>
                      <nav>
                        <ul className="pagination mb-0" style={{ background: '#fff', borderRadius: 10, boxShadow: '0 1px 6px #2563eb11', padding: '6px 14px', display: 'flex', flexWrap: 'nowrap', gap: 4 }}>
                          <li className={`page-item${page === 1 ? ' disabled' : ''}`}> <button className="page-link" style={{ border: 'none', background: 'none', color: '#2563eb', fontWeight: 600, fontSize: '1rem', borderRadius: 7, padding: '4px 10px', transition: 'background 0.2s' }} onClick={() => handlePageChange(page - 1)}>&laquo;</button></li>
                          {[...Array(totalPages)].map((_, idx) => (
                            <li key={idx} className={`page-item${page === idx + 1 ? ' active' : ''}`}> <button className="page-link" style={{ border: 'none', background: idx + 1 === page ? 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)' : 'none', color: idx + 1 === page ? '#fff' : '#0078d4', fontWeight: 600, fontSize: '1rem', borderRadius: 7, margin: '0 2px', minWidth: 28, padding: '4px 10px', boxShadow: idx + 1 === page ? '0 1px 4px #0078d422' : 'none', transition: 'background 0.2s, color 0.2s' }} onClick={() => handlePageChange(idx + 1)}>{idx + 1}</button></li>
                          ))}
                          <li className={`page-item${page === totalPages ? ' disabled' : ''}`}> <button className="page-link" style={{ border: 'none', background: 'none', color: '#2563eb', fontWeight: 600, fontSize: '1rem', borderRadius: 7, padding: '4px 10px', transition: 'background 0.2s' }} onClick={() => handlePageChange(page + 1)}>&raquo;</button></li>
                        </ul>
                      </nav>
                    </div>
                  )}
                </div>
              ) : (
                <div>
                  <div className="mb-4">
                    <h5 className="mb-3">RFID Device Details</h5>
                    <div className="row g-3 align-items-end">
                      <div className="col-md-4">
                        <label className="form-label">Device ID</label>
                        <input
                          type="text"
                          className="form-control"
                          value={deviceId}
                          onChange={(e) => setDeviceId(e.target.value)}
                          placeholder="Enter Device ID"
                          style={{ borderRadius: '8px' }}
                        />
                      </div>
                      <div className="col-md-4">
                        <label className="form-label">Client Code</label>
                        <input
                          type="text"
                          className="form-control"
                          value={userInfo.ClientCode || ''}
                          disabled
                          style={{ 
                            borderRadius: '8px',
                            backgroundColor: '#f8f9fa'
                          }}
                        />
                      </div>
                      <div className="col-md-4">
                        <button
                          className="btn btn-primary w-100"
                          onClick={handleGetRFIDDetails}
                          disabled={loading}
                          style={{
                            borderRadius: '8px',
                            background: 'linear-gradient(135deg, #4A00E0, #8E2DE2)',
                            border: 'none'
                          }}
                        >
                          {loading ? (
                            <>
                              <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                              Loading...
                            </>
                          ) : (
                            <>
                              <i className="fas fa-search me-2"></i>
                              Get Details
                            </>
                          )}
                        </button>
                      </div>
                    </div>
                  </div>

                  {/* RFID Details Table */}
                  <div className="table-responsive" style={{ 
                    maxHeight: '500px',
                    overflowY: 'auto',
                    borderRadius: '10px',
                    border: '1px solid #dee2e6',
                    boxShadow: '0 4px 12px rgba(0,0,0,0.1)'
                  }}>
                    <table className="table table-hover mb-0">
                      <thead style={{ 
                        position: 'sticky',
                        top: 0,
                        background: 'linear-gradient(135deg, #4A00E0, #8E2DE2)',
                        color: 'white'
                      }}>
                        <tr>
                          <th style={{ padding: '12px 16px' }}>RFID Code</th>
                          <th style={{ padding: '12px 16px' }}>TID Value</th>
                          <th style={{ padding: '12px 16px' }}>Device ID</th>
                          <th style={{ padding: '12px 16px' }}>Client Code</th>
                          <th style={{ padding: '12px 16px' }}>Created On</th>
                          <th style={{ padding: '12px 16px' }}>Last Updated</th>
                          <th style={{ padding: '12px 16px' }}>Status</th>
                        </tr>
                      </thead>
                      <tbody>
                        {rfidDetails.length > 0 ? (
                          rfidDetails.map((item, index) => (
                            <tr key={item.Id || index} style={{
                              transition: 'background-color 0.2s',
                              cursor: 'pointer'
                            }}
                            onMouseEnter={(e) => e.currentTarget.style.backgroundColor = '#f8f9fa'}
                            onMouseLeave={(e) => e.currentTarget.style.backgroundColor = 'transparent'}
                            >
                              <td style={{ padding: '12px 16px' }}>{item.RFIDCode}</td>
                              <td style={{ padding: '12px 16px' }}>{item.TIDValue}</td>
                              <td style={{ padding: '12px 16px' }}>{item.DeviceId}</td>
                              <td style={{ padding: '12px 16px' }}>{item.ClientCode}</td>
                              <td style={{ padding: '12px 16px' }}>
                                {new Date(item.CreatedOn).toLocaleString()}
                              </td>
                              <td style={{ padding: '12px 16px' }}>
                                {new Date(item.LastUpdated).toLocaleString()}
                              </td>
                              <td style={{ padding: '12px 16px' }}>
                                <span className={`badge ${item.StatusType ? 'bg-success' : 'bg-danger'}`}
                                      style={{
                                        padding: '6px 12px',
                                        borderRadius: '12px',
                                        fontWeight: '500',
                                        fontSize: '12px'
                                      }}>
                                  {item.StatusType ? 'Active' : 'Inactive'}
                                </span>
                              </td>
                            </tr>
                          ))
                        ) : (
                          <tr>
                            <td colSpan="7" className="text-center py-4" style={{
                              color: '#6c757d',
                              fontSize: '15px',
                              fontWeight: '500'
                            }}>
                              {loading ? (
                                <div className="d-flex align-items-center justify-content-center">
                                  <div className="spinner-border spinner-border-sm me-2" role="status">
                                    <span className="visually-hidden">Loading...</span>
                                  </div>
                                  Loading RFID details...
                                </div>
                              ) : 'No RFID details found'}
                            </td>
                          </tr>
                        )}
                      </tbody>
                    </table>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
      {/* Export Success Modal */}
      {showExportSuccess && (
        <div style={{
          position: 'fixed',
          top: 0,
          left: 0,
          width: '100vw',
          height: '100vh',
          background: 'rgba(0,0,0,0.18)',
          zIndex: 9999,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
        }}>
          <div style={{
            background: 'linear-gradient(135deg, #fff 0%, #f8f9fa 100%)',
            borderRadius: 22,
            boxShadow: '0 8px 32px #0078d422',
            padding: '2.5rem 2.5rem 2rem 2.5rem',
            minWidth: 320,
            maxWidth: 380,
            textAlign: 'center',
            fontFamily: 'Poppins, Inter, sans-serif',
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            gap: 18,
            position: 'relative',
            border: '2px solid #e0e6ed',
            overflow: 'hidden'
          }}>
            <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: 8, background: 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)', borderTopLeftRadius: 22, borderTopRightRadius: 22 }}></div>
            <FaCheckCircle size={48} style={{ color: 'url(#blueRedGradient)', filter: 'drop-shadow(0 2px 8px #0078d4aa)' }} />
            <svg width="0" height="0">
              <linearGradient id="blueRedGradient" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop stopColor="#0078d4" offset="0%" />
                <stop stopColor="#d60000" offset="100%" />
              </linearGradient>
            </svg>
            <div style={{ fontWeight: 700, fontSize: 22, color: '#0078d4', marginBottom: 8, background: 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>File exported successfully.</div>
            <button
              onClick={() => setShowExportSuccess(false)}
              style={{
                background: 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)',
                color: '#fff',
                border: 'none',
                borderRadius: 10,
                padding: '12px 32px',
                fontWeight: 700,
                fontSize: 16,
                cursor: 'pointer',
                boxShadow: '0 2px 12px #0078d422',
                marginTop: 8,
                fontFamily: 'Poppins, Inter, sans-serif',
                transition: 'background 0.2s, transform 0.2s',
              }}
              onMouseOver={e => {
                e.currentTarget.style.background = 'linear-gradient(90deg, #d60000 0%, #0078d4 100%)';
                e.currentTarget.style.transform = 'scale(1.04)';
              }}
              onMouseOut={e => {
                e.currentTarget.style.background = 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)';
                e.currentTarget.style.transform = 'scale(1)';
              }}
            >
              Close
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default Inventory;
